return [
  {
    json: {
      caseId: 'pass-basic-ticket',
      requestId: 'req_demo_001',
      taskType: 'summarize_ticket',
      payload: {
        ticketId: 'TICKET-123',
        text: 'Synthetic customer note for QA testing.'
      }
    }
  },
  {
    json: {
      caseId: 'fail-missing-task-type',
      requestId: 'req_demo_002',
      payload: {
        ticketId: 'TICKET-124',
        text: 'Synthetic note with a missing taskType.'
      }
    }
  }
];

return items.map((item) => {
  const value = item.json;
  const missing = [];
  for (const field of ['requestId', 'taskType', 'payload']) {
    if (value[field] === undefined || value[field] === null || value[field] === '') {
      missing.push(field);
    }
  }

  const passed = missing.length === 0;
  return {
    json: {
      caseId: value.caseId,
      passed,
      missing,
      sanitizedInput: value,
      recommendation: passed
        ? 'Input contract looks valid. Continue to downstream workflow nodes.'
        : `Reject or route to repair branch. Missing: ${missing.join(', ')}`
    }
  };
});

const passed = items.filter((item) => item.json.passed).length;
const failed = items.length - passed;
return [
  {
    json: {
      status: failed === 0 ? 'pass' : 'needs_attention',
      totalCases: items.length,
      passed,
      failed,
      cases: items.map((item) => item.json),
      nextStep: failed === 0
        ? 'Attach this validation block before the production workflow body.'
        : 'Fix required fields or add a repair branch before expensive API or AI calls.'
    }
  }
];
